// Auto-generated: fonts embedded as base64 so rendering has zero runtime
// file/CDN dependency (works identically on edge, node, and locally). Regenerate
// by base64-encoding the files in fonts/.
export const INTER_500 = ""
export const INTER_800 = ""
export const BEBAS = ""

export function toBuf(b64) {
  const bin = atob(b64)
  const buf = new Uint8Array(bin.length)
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i)
  return buf.buffer
}
